public class Curry {
    static java.util.function.Function<Integer,java.util.function.Function<Integer,Integer>> add =
        a -> b -> a + b;
    public static void main(String[] args) {
        var add5 = add.apply(5);
        System.out.println(add5.apply(3));
        System.out.println(add5.apply(10));
        System.out.println(add.apply(1).apply(2));
    }
}
